const text = ($input.first().json.text || '').toString();
const size = 1200;
const overlap = 100;
const chunks = [];
let i = 0;
while (i < text.length) {
  const end = Math.min(i + size, text.length);
  const piece = text.slice(i, end).trim();
  if (piece.length > 0) chunks.push(piece);
  if (end === text.length) break;
  i += (size - overlap);
}
return chunks.map((c, idx) => ({ json: { chunk_id: idx + 1, chunk_text: c } }));

const embItems = $input.all();
const chunks = $('Нарезка на чанки').all();
const points = embItems.map((it, idx) => {
  const emb = it.json.data[0].embedding.map(Number);
  return {
    id: idx + 1,
    vector: emb,
    payload: { text: chunks[idx].json.chunk_text }
  };
});
return [{ json: { points } }];
